1043	    const cs = raw.closureStatus ?? raw.closure_status;
1044	    const closureStatus =
1045	      cs === 'open' || cs === 'resolved' || cs === 'accepted' || cs === 'deferred'
1046	        ? cs
1047	        : ('resolved' as const);
1048	    return {
1049	      kind: 'agent_assumption',
1050	      id,
1051	      statement: typeof raw.statement === 'string' ? raw.statement : '',
1052	      source,
1053	      ...(closureStatus !== 'resolved' ? { closureStatus } : {}),
1054	      ...(relatedElementIds.length ? { relatedElementIds } : {}),
1055	      relatedTopicId: (raw.relatedTopicId ?? raw.related_topic_id ?? null) as string | null,
1056	    };
1057	  }
1058	
1059	  if (kind === 'agent_deviation') {
1060	    const sev = raw.severity;
1061	    const severity =
1062	      sev === 'info' || sev === 'warning' || sev === 'error' ? sev : ('warning' as const);
1063	    const ack = raw.acknowledged;
1064	    const acknowledged = typeof ack === 'boolean' ? ack : true;
1065	    const relatedRaw = raw.relatedElementIds ?? raw.related_element_ids ?? [];
1066	    const relatedElementIds =
1067	      Array.isArray(relatedRaw) && relatedRaw.every((x) => typeof x === 'string')
1068	        ? [...relatedRaw].sort()
1069	        : [];
1070	    return {
1071	      kind: 'agent_deviation',
1072	      id,
1073	      statement: typeof raw.statement === 'string' ? raw.statement : '',
1074	      severity,
1075	      ...(acknowledged ? {} : { acknowledged: false }),
1076	      relatedAssumptionId: (raw.relatedAssumptionId ?? raw.related_assumption_id ?? null) as
1077	        | string
1078	        | null,
1079	      ...(relatedElementIds.length ? { relatedElementIds } : {}),
1080	    };
1081	  }
1082	
1083	  if (kind === 'plan_tag_style') {
1084	    const ttRaw = raw.tagTarget ?? raw.tag_target;
1085	    const tagTarget: 'opening' | 'room' = ttRaw === 'room' ? 'room' : 'opening';
1086	    const lfRaw = raw.labelFields ?? raw.label_fields;
1087	    const labelFields = Array.isArray(lfRaw)
1088	      ? lfRaw.filter((x): x is string => typeof x === 'string')
1089	      : [];
1090	    const bs = raw.badgeStyle ?? raw.badge_style;
1091	    const badgeStyle = bs === 'rounded' || bs === 'flag' ? bs : ('none' as const);
1092	    const tsp = Number(raw.textSizePt ?? raw.text_size_pt ?? 10);
1093	    return {
1094	      kind: 'plan_tag_style',
1095	      id,
1096	      name,
1097	      tagTarget,
1098	      labelFields,
1099	      textSizePt: Number.isFinite(tsp) && tsp > 0 ? tsp : 10,
1100	      leaderVisible: readViewTemplateBool(raw.leaderVisible ?? raw.leader_visible, true),
1101	      badgeStyle,
1102	      colorToken:
1103	        typeof raw.colorToken === 'string' || typeof raw.color_token === 'string'
1104	          ? String(raw.colorToken ?? raw.color_token)
1105	          : 'default',
1106	      sortKey: Number(raw.sortKey ?? raw.sort_key ?? 0) || 0,
1107	    };
1108	  }
1109	
1110	  if (kind === 'validation_rule') {
1111	    return {
1112	      kind: 'validation_rule',
1113	      id,
1114	      name,
1115	      ruleJson: (typeof raw.ruleJson === 'object' && raw.ruleJson
1116	        ? raw.ruleJson
1117	        : typeof raw.rule_json === 'object' && raw.rule_json
1118	          ? raw.rule_json
1119	          : {}) as Record<string, unknown>,
1120	    };
1121	  }
1122	
1123	  return null;
1124	}
